1	//! sled K/V 存储
2	//!
3	//! 提供符号、边、导入关系的持久化存储。
4	//! 命名空间通过键前缀实现：
5	//!
6	//! | 前缀 | 用途 |
7	//! |------|------|
8	//! | `meta:` | 文件元信息 |
9	//! | `symbols:` | 符号定义 |
10	//! | `edges:` | 调用边 |
11	//! | `refs:` | 引用边 |
12	//! | `imports:` | 导入信息 |
13	//! | `file_symbols:` | 文件→符号映射 |
14	//! | `neighbors:` | 邻接表 |
15	//! | `index_meta:` | 索引元信息（指纹、版本） |
16	
17	use std::path::Path;
18	use sled::Db;
19	use codeconnect_core::error::CodeConnectError;
20	
21	/// 键前缀常量
22	const PREFIX_META: &str = "meta:";
23	const PREFIX_SYMBOLS: &str = "symbols:";
24	const PREFIX_EDGES: &str = "edges:";
25	const PREFIX_REFS: &str = "refs:";
26	const PREFIX_IMPORTS: &str = "imports:";
27	const PREFIX_FILE_SYMBOLS: &str = "file_symbols:";
28	const PREFIX_NEIGHBORS: &str = "neighbors:";
29	const PREFIX_INDEX_META: &str = "index_meta:";
30	
31	/// sled 存储管理器
32	///
33	/// 基于 sled 嵌入式数据库提供持久化 K/V 存储。
34	/// 所有数据以字节形式存储，上层负责序列化/反序列化。
35	pub struct SledStore {
36	    db: Db,
37	}
38	
39	impl SledStore {
40	    /// 打开或创建 sled 数据库
41	    ///
42	    /// # 参数
43	    /// - `path` — 数据库目录路径，目录不存在时会自动创建
44	    pub fn open(path: &Path) -> Result<Self, CodeConnectError> {
45	        let db = sled::open(path)
46	            .map_err(|e| CodeConnectError::Index(format!("无法打开 sled: {}", e)))?;
47	        Ok(Self { db })
48	    }
49	
50	    // ===== 文件元信息 =====
51	
52	    /// 存储文件元信息
53	    ///
54	    /// `data` 应为 `FileMeta` 的序列化（JSON/bincode）字节。
55	    pub fn put_file_meta(&self, file_path: &str, data: &[u8]) -> Result<(), CodeConnectError> {
56	        let key = format!("{}{}", PREFIX_META, file_path);
57	        self.db
58	            .insert(key.as_bytes(), data)
59	            .map_err(|e| CodeConnectError::Index(format!("写入文件元信息失败: {}", e)))?;
60	        Ok(())
61	    }
62	
63	    /// 读取文件元信息
64	    ///
65	    /// 返回 `None` 表示该文件尚无元信息记录。
66	    pub fn get_file_meta(&self, file_path: &str) -> Result<Option<Vec<u8>>, CodeConnectError> {
67	        let key = format!("{}{}", PREFIX_META, file_path);
68	        Ok(self
69	            .db
70	            .get(key.as_bytes())
71	            .map_err(|e| CodeConnectError::Index(format!("读取文件元信息失败: {}", e)))?
72	            .map(|v| v.to_vec()))
73	    }
74	
75	    /// 删除文件元信息
76	    pub fn remove_file_meta(&self, file_path: &str) -> Result<(), CodeConnectError> {
77	        let key = format!("{}{}", PREFIX_META, file_path);
78	        self.db
79	            .remove(key.as_bytes())
80	            .map_err(|e| CodeConnectError::Index(format!("删除文件元信息失败: {}", e)))?;
81	        Ok(())
82	    }
83	
84	    // ===== 符号定义 =====
85	
86	    /// 存储符号定义
87	    ///
88	    /// `data` 应为 `Symbol` 的序列化字节。
89	    pub fn put_symbol(&self, stable_id: &str, data: &[u8]) -> Result<(), CodeConnectError> {
90	        let key = format!("{}{}", PREFIX_SYMBOLS, stable_id);
91	        self.db
92	            .insert(key.as_bytes(), data)
93	            .map_err(|e| CodeConnectError::Index(format!("写入符号失败: {}", e)))?;
94	        Ok(())
95	    }
96	
97	    /// 读取符号定义
98	    ///
99	    /// 返回 `None` 表示该符号不存在。
100	    pub fn get_symbol(&self, stable_id: &str) -> Result<Option<Vec<u8>>, CodeConnectError> {
101	        let key = format!("{}{}", PREFIX_SYMBOLS, stable_id);
102	        Ok(self
103	            .db
104	            .get(key.as_bytes())
105	            .map_err(|e| CodeConnectError::Index(format!("读取符号失败: {}", e)))?
106	            .map(|v| v.to_vec()))
107	    }
108	
109	    /// 删除符号定义
110	    pub fn delete_symbol(&self, stable_id: &str) -> Result<(), CodeConnectError> {
111	        let key = format!("{}{}", PREFIX_SYMBOLS, stable_id);
112	        self.db
113	            .remove(key.as_bytes())
114	            .map_err(|e| CodeConnectError::Index(format!("删除符号失败: {}", e)))?;
115	        Ok(())
116	    }
117	
118	    /// 批量存储符号（使用原子批处理）
119	    pub fn put_symbols_batch(
120	        &self,
121	        entries: &[(&str, &[u8])],
122	    ) -> Result<(), CodeConnectError> {
123	        let mut batch = sled::Batch::default();
124	        for (stable_id, data) in entries {
125	            let key = format!("{}{}", PREFIX_SYMBOLS, stable_id);
126	            batch.insert(key.as_bytes(), *data);
127	        }
128	        self.db
129	            .apply_batch(batch)
130	            .map_err(|e| CodeConnectError::Index(format!("批量写入符号失败: {}", e)))?;
131	        Ok(())
132	    }
133	
134	    // ===== 调用边 =====
135	
136	    /// 存储调用边
137	    ///
138	    /// `data` 应为 `CallEdge` 的序列化字节。
139	    pub fn put_call_edge(
140	        &self,
141	        caller_id: &str,
142	        callee_id: &str,
143	        data: &[u8],
144	    ) -> Result<(), CodeConnectError> {
145	        let key = format!("{}{}::{}", PREFIX_EDGES, caller_id, callee_id);
146	        self.db
147	            .insert(key.as_bytes(), data)
148	            .map_err(|e| CodeConnectError::Index(format!("写入调用边失败: {}", e)))?;
149	        Ok(())
150	    }
151	
152	    /// 读取调用边
153	    pub fn get_call_edge(
154	        &self,
155	        caller_id: &str,
156	        callee_id: &str,
157	    ) -> Result<Option<Vec<u8>>, CodeConnectError> {
158	        let key = format!("{}{}::{}", PREFIX_EDGES, caller_id, callee_id);
159	        Ok(self
160	            .db
161	            .get(key.as_bytes())
162	            .map_err(|e| CodeConnectError::Index(format!("读取调用边失败: {}", e)))?
163	            .map(|v| v.to_vec()))
164	    }
165	
166	    /// 删除调用边
167	    pub fn remove_call_edge(
168	        &self,
169	        caller_id: &str,
170	        callee_id: &str,
171	    ) -> Result<(), CodeConnectError> {
172	        let key = format!("{}{}::{}", PREFIX_EDGES, caller_id, callee_id);
173	        self.db
174	            .remove(key.as_bytes())
175	            .map_err(|e| CodeConnectError::Index(format!("删除调用边失败: {}", e)))?;
176	        Ok(())
177	    }
178	
179	    /// 获取某个调用者的所有出边
180	    ///
181	    /// 遍历以 `edges:{caller_id}::` 为前缀的所有键。
182	    pub fn get_call_edges_from(
183	        &self,
184	        caller_id: &str,
185	    ) -> Result<Vec<(String, Vec<u8>)>, CodeConnectError> {
186	        let prefix = format!("{}{}::", PREFIX_EDGES, caller_id);
187	        let mut results = Vec::new();
188	        for item in self.db.scan_prefix(prefix.as_bytes()) {
189	            let (key, value) =
190	                item.map_err(|e| CodeConnectError::Index(format!("扫描调用边失败: {}", e)))?;
191	            results.push((String::from_utf8_lossy(&key).to_string(), value.to_vec()));
192	        }
193	        Ok(results)
194	    }
195	
196	    // ===== 引用边 =====
197	
198	    /// 存储引用边
199	    ///
200	    /// `data` 应为 `RefEdge` 的序列化字节。
201	    pub fn put_ref_edge(
202	        &self,
203	        ref_id: &str,
204	        target_id: &str,
205	        data: &[u8],
206	    ) -> Result<(), CodeConnectError> {
207	        let key = format!("{}{}::{}", PREFIX_REFS, ref_id, target_id);
208	        self.db
209	            .insert(key.as_bytes(), data)
210	            .map_err(|e| CodeConnectError::Index(format!("写入引用边失败: {}", e)))?;
211	        Ok(())
212	    }
213	
214	    /// 读取引用边
215	    pub fn get_ref_edge(
216	        &self,
217	        ref_id: &str,
218	        target_id: &str,
219	    ) -> Result<Option<Vec<u8>>, CodeConnectError> {
220	        let key = format!("{}{}::{}", PREFIX_REFS, ref_id, target_id);
221	        Ok(self
222	            .db
223	            .get(key.as_bytes())
224	            .map_err(|e| CodeConnectError::Index(format!("读取引用边失败: {}", e)))?
225	            .map(|v| v.to_vec()))
226	    }
227	
228	    // ===== 导入关系 =====
229	
230	    /// 存储导入信息
231	    ///
232	    /// `data` 应为 `Import` 的序列化字节。
233	    pub fn put_import(
234	        &self,
235	        file_path: &str,
236	        import_path: &str,
237	        data: &[u8],
238	    ) -> Result<(), CodeConnectError> {
239	        let key = format!("{}{}::{}", PREFIX_IMPORTS, file_path, import_path);
240	        self.db
241	            .insert(key.as_bytes(), data)
242	            .map_err(|e| CodeConnectError::Index(format!("写入导入信息失败: {}", e)))?;
243	        Ok(())
244	    }
245	
246	    /// 获取某个文件的所有导入
247	    pub fn get_imports_for_file(
248	        &self,
249	        file_path: &str,
250	    ) -> Result<Vec<Vec<u8>>, CodeConnectError> {
251	        let prefix = format!("{}{}::", PREFIX_IMPORTS, file_path);
252	        let mut results = Vec::new();
253	        for item in self.db.scan_prefix(prefix.as_bytes()) {
254	            let (_, value) =
255	                item.map_err(|e| CodeConnectError::Index(format!("扫描导入失败: {}", e)))?;
256	            results.push(value.to_vec());
257	        }
258	        Ok(results)
259	    }
260	
261	    // ===== 文件→符号映射 =====
262	
263	    /// 存储文件→符号列表的映射
264	    ///
265	    /// `data` 应为符号 ID 列表的序列化字节（如 JSON 数组）。
266	    pub fn put_file_symbols(
267	        &self,
268	        file_path: &str,
269	        data: &[u8],
270	    ) -> Result<(), CodeConnectError> {
271	        let key = format!("{}{}", PREFIX_FILE_SYMBOLS, file_path);
272	        self.db
273	            .insert(key.as_bytes(), data)
274	            .map_err(|e| CodeConnectError::Index(format!("写入文件符号映射失败: {}", e)))?;
275	        Ok(())
276	    }
277	
278	    /// 读取文件→符号列表的映射
279	    pub fn get_file_symbols(&self, file_path: &str) -> Result<Option<Vec<u8>>, CodeConnectError> {
280	        let key = format!("{}{}", PREFIX_FILE_SYMBOLS, file_path);
281	        Ok(self
282	            .db
283	            .get(key.as_bytes())
284	            .map_err(|e| CodeConnectError::Index(format!("读取文件符号映射失败: {}", e)))?
285	            .map(|v| v.to_vec()))
286	    }
287	
288	    /// 删除文件→符号映射
289	    pub fn remove_file_symbols(&self, file_path: &str) -> Result<(), CodeConnectError> {
290	        let key = format!("{}{}", PREFIX_FILE_SYMBOLS, file_path);
291	        self.db
292	            .remove(key.as_bytes())
293	            .map_err(|e| CodeConnectError::Index(format!("删除文件符号映射失败: {}", e)))?;
294	        Ok(())
295	    }
296	
297	    // ===== 邻接表 =====
298	
299	    /// 存储符号的邻接表
300	    ///
301	    /// `data` 应为相邻符号 ID 列表的序列化字节。
302	    pub fn put_neighbors(
303	        &self,
304	        symbol_id: &str,
305	        data: &[u8],
306	    ) -> Result<(), CodeConnectError> {
307	        let key = format!("{}{}", PREFIX_NEIGHBORS, symbol_id);
308	        self.db
309	            .insert(key.as_bytes(), data)
310	            .map_err(|e| CodeConnectError::Index(format!("写入邻接表失败: {}", e)))?;
311	        Ok(())
312	    }
313	
314	    /// 读取符号的邻接表
315	    pub fn get_neighbors(&self, symbol_id: &str) -> Result<Option<Vec<u8>>, CodeConnectError> {
316	        let key = format!("{}{}", PREFIX_NEIGHBORS, symbol_id);
317	        Ok(self
318	            .db
319	            .get(key.as_bytes())
320	            .map_err(|e| CodeConnectError::Index(format!("读取邻接表失败: {}", e)))?
321	            .map(|v| v.to_vec()))
322	    }
323	
324	    // ===== 文件指纹 =====
325	
326	    /// 存储文件指纹（内容哈希）
327	    ///
328	    /// 用于增量索引时检测文件是否变更。
329	    pub fn put_fingerprint(
330	        &self,
331	        file_path: &str,
332	        data: &[u8],
333	    ) -> Result<(), CodeConnectError> {
334	        let key = format!("{}fingerprint:{}", PREFIX_INDEX_META, file_path);
335	        self.db
336	            .insert(key.as_bytes(), data)
337	            .map_err(|e| CodeConnectError::Index(format!("写入文件指纹失败: {}", e)))?;
338	        Ok(())
339	    }
340	
341	    /// 读取文件指纹
342	    pub fn get_fingerprint(&self, file_path: &str) -> Result<Option<Vec<u8>>, CodeConnectError> {
343	        let key = format!("{}fingerprint:{}", PREFIX_INDEX_META, file_path);
344	        Ok(self
345	            .db
346	            .get(key.as_bytes())
347	            .map_err(|e| CodeConnectError::Index(format!("读取文件指纹失败: {}", e)))?
348	            .map(|v| v.to_vec()))
349	    }
350	
351	    /// 删除文件指纹
352	    pub fn remove_fingerprint(&self, file_path: &str) -> Result<(), CodeConnectError> {
353	        let key = format!("{}fingerprint:{}", PREFIX_INDEX_META, file_path);
354	        self.db
355	            .remove(key.as_bytes())
356	            .map_err(|e| CodeConnectError::Index(format!("删除文件指纹失败: {}", e)))?;
357	        Ok(())
358	    }
359	
360	    // ===== Schema 版本 =====
361	
362	    /// 存储 Schema 版本号
363	    ///
364	    /// 用于索引迁移时检测是否需要重建索引。
365	    pub fn put_schema_version(&self, version: u32) -> Result<(), CodeConnectError> {
366	        let key = format!("{}schema_version", PREFIX_INDEX_META);
367	        let data = version.to_le_bytes();
368	        self.db
369	            .insert(key.as_bytes(), &data[..])
370	            .map_err(|e| CodeConnectError::Index(format!("写入版本失败: {}", e)))?;
371	        Ok(())
372	    }
373	
374	    /// 读取 Schema 版本号
375	    ///
376	    /// 返回 `None` 表示版本信息尚未写入（旧版本索引）。
377	    pub fn get_schema_version(&self) -> Result<Option<u32>, CodeConnectError> {
378	        let key = format!("{}schema_version", PREFIX_INDEX_META);
379	        Ok(self
380	            .db
381	            .get(key.as_bytes())
382	            .map_err(|e| CodeConnectError::Index(format!("读取版本失败: {}", e)))?
383	            .map(|v| {
384	                let mut arr = [0u8; 4];
385	                let len = 4.min(v.len());
386	                arr[..len].copy_from_slice(&v[..len]);
387	                u32::from_le_bytes(arr)
388	            }))
389	    }
390	
391	    // ===== 批量操作 =====
392	
393	    /// 批处理：原子地执行多个键值对操作
394	    ///
395	    /// 接受插入和删除操作列表，在单次事务中提交。
396	    pub fn apply_batch(
397	        &self,
398	        inserts: &[(&[u8], &[u8])],
399	        removals: &[&[u8]],
400	    ) -> Result<(), CodeConnectError> {
401	        let mut batch = sled::Batch::default();
402	        for (key, value) in inserts {
403	            batch.insert(*key, *value);
404	        }
405	        for key in removals {
406	            batch.remove(*key);
407	        }
408	        self.db
409	            .apply_batch(batch)
410	            .map_err(|e| CodeConnectError::Index(format!("批处理失败: {}", e)))?;
411	        Ok(())
412	    }
413	
414	    /// 扫描指定前缀的所有键值对
415	    pub fn scan_prefix(
416	        &self,
417	        prefix: &[u8],
418	    ) -> impl Iterator<Item = Result<(Vec<u8>, Vec<u8>), CodeConnectError>> + '_ {
419	        self.db.scan_prefix(prefix).map(|item| {
420	            item.map(|(k, v)| (k.to_vec(), v.to_vec()))
421	                .map_err(|e| CodeConnectError::Index(format!("扫描失败: {}", e)))
422	        })
423	    }
424	
425	    // ===== 生命周期 =====
426	
427	    /// 刷写所有待写入数据到磁盘
428	    pub fn flush(&self) -> Result<(), CodeConnectError> {
429	        self.db
430	            .flush()
431	            .map_err(|e| CodeConnectError::Index(format!("刷写失败: {}", e)))?;
432	        Ok(())
433	    }
434	
435	    /// 获取数据库中的近似条目数
436	    pub fn size(&self) -> usize {
437	        self.db.len()
438	    }
439	
440	    /// 检查数据库中是否包含指定键
441	    pub fn contains_key(&self, key: &[u8]) -> Result<bool, CodeConnectError> {
442	        self.db
443	            .contains_key(key)
444	            .map_err(|e| CodeConnectError::Index(format!("检查键失败: {}", e)))
445	    }
446	}
