//! 导入解析器
//!
//! 将调用点的被调用者名称解析为稳定的符号 ID。
//! 每种语言实现自己的导入解析策略（同文件、同包、外部依赖等），
//! 支持候选目标列表和置信度评分。

use std::collections::HashMap;
use std::path::{Path, PathBuf};

use codeconnect_core::error::CodeConnectError;

/// 解析结果
///
/// 包含候选目标符号列表和解析策略描述。
#[derive(Debug, Clone)]
pub struct ResolutionResult {
    /// 候选目标符号列表（按置信度降序排列）
    pub candidates: Vec<CandidateTarget>,
    /// 解析策略描述（如 "同文件匹配"、"use 导入解析"、"外部 crate" 等）
    pub strategy: String,
}

/// 候选目标
///
/// 描述一个可能被调用的符号目标及其匹配置信度。
#[derive(Debug, Clone)]
pub struct CandidateTarget {
    /// 目标符号的稳定 ID
    pub symbol_id: String,
    /// 匹配置信度（0.0 表示猜测，1.0 表示精确匹配）
    pub confidence: f64,
    /// 可读的解析路径说明（如 "import:std::io::Read -> resolved"）
    pub resolution_path: String,
}

/// 导入解析器 trait
///
/// 每种语言的解析器实现此 trait，提供跨文件调用目标解析能力。
/// 解析策略因语言而异：
/// - Rust：按 `use` 语句 → 同模块 → 同 crate → 外部依赖 的优先级搜索
/// - TypeScript/JavaScript：按 `import` → 同目录 → node_modules 搜索
/// - Java：按 `import` → 同包 → classpath 搜索
/// - C#：按 `using` → 同命名空间 → 项目引用 → NuGet 搜索
pub trait ImportResolver: Send + Sync {
    /// 返回此解析器支持的语言名称（如 "rust", "java"）
    fn language(&self) -> &'static str;

    /// 解析调用目标
    ///
    /// 根据被调用者名称、调用者文件和文件的导入映射，
    /// 推断被调用符号的稳定 ID 候选列表。
    ///
    /// # 参数
    /// - `callee_name` — 被调用者名称（简单名如 `HashMap` 或部分限定名如 `std::collections::HashMap`）
    /// - `caller_file` — 调用发生的源文件路径
    /// - `imports` — 调用者文件内的导入映射（导入语句 → 已解析的符号 ID 列表）
    ///
    /// # 返回值
    /// 候选目标列表（按置信度降序）和解析策略说明。
    /// 空列表表示无法解析（如系统库或未索引的依赖）。
    fn resolve(
        &self,
        callee_name: &str,
        caller_file: &Path,
        imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError>;

    /// 尝试定位一个外部模块的文件路径
    ///
    /// 根据模块路径和参考文件位置，在项目中查找对应的源文件。
    ///
    /// # 参数
    /// - `module_path` — 模块路径（如 `std::collections` 或 `./util`）
    /// - `from_file` — 参考文件路径（用于计算相对路径的基准）
    ///
    /// # 返回值
    /// - `Some(PathBuf)` 表示找到了对应的源文件路径
    /// - `None` 表示无法解析（如系统库、标准库或外部依赖）
    fn locate_module(&self, module_path: &str, from_file: &Path) -> Option<PathBuf>;
}

// ===== 各语言导入解析器实现 =====

/// Rust 导入解析器
///
/// Rust 的导入解析按以下优先级进行：
/// 1. 同文件内查找（当前模块内定义的所有符号）
/// 2. `use` 语句导入的符号（来自 `sandbox_params`）
/// 3. 同 crate 内通过 `mod` 树可访问的符号
/// 4. `Cargo.toml` 中声明依赖的外部 crate（标记为 external）
pub struct RustImportResolver;

impl ImportResolver for RustImportResolver {
    fn language(&self) -> &'static str {
        "rust"
    }

    fn resolve(
        &self,
        _callee_name: &str,
        _caller_file: &Path,
        _imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError> {
        // TODO: 实现 Rust use 语句解析
        // 策略：
        // 1. 同文件内查找（当前模块可见的所有符号）
        // 2. 同 crate 内查找（通过 mod 树遍历）
        // 3. use 导入的符号（来自 imports 参数）
        // 4. Cargo.toml 依赖的外部 crate（标记为 external）
        Ok(ResolutionResult {
            candidates: vec![],
            strategy: "rust_local_only".to_string(),
        })
    }

    fn locate_module(&self, _module_path: &str, _from_file: &Path) -> Option<PathBuf> {
        // TODO: 根据 Rust 模块路径规则定位源文件
        // 1. 检查 module_path.rs 是否存在
        // 2. 检查 module_path/mod.rs 是否存在
        // 3. 对于外部 crate，在 target/ 或 ~/.cargo/registry 中查找
        None
    }
}

