        // 3. 同目录下的 index.ts / 命名导出
        // 4. node_modules 中的包
        Ok(ResolutionResult {
            candidates: vec![],
            strategy: "ts_local_only".to_string(),
        })
    }

    fn locate_module(&self, _module_path: &str, _from_file: &Path) -> Option<PathBuf> {
