/// Java 导入解析器
pub struct JavaImportResolver;

impl ImportResolver for JavaImportResolver {
    fn language(&self) -> &'static str {
        "java"
    }

    fn resolve(
        &self,
        _callee_name: &str,
        _caller_file: &Path,
        _imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError> {
        // TODO: 实现 Java import 解析
        // 策略：
        // 1. 同文件内查找（当前类/接口的方法）
        // 2. 同包下的其他类（无需 import）
        // 3. import 语句导入的类/静态方法
        // 4. java.lang.* 自动导入
        // 5. classpath 上的外部 jar
        Ok(ResolutionResult {
            candidates: vec![],
            strategy: "java_local_only".to_string(),
