fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
    // Rust 项目：从 Cargo.toml 所在目录名推断 crate 名
    // 此处简化，使用文件路径的根级目录名
    let components: Vec<_> = file_path.components().collect();
    for component in components.iter().rev() {
        if let std::path::Component::Normal(name) = component {
            if name == "src" {
                continue;
            }
            return name.to_str().map(|s| s.to_string());
        }
    }
    None
}

/// one match may contain captures that appear *before* some of the
/// captures from a previous match.
#[doc(alias = "ts_query_cursor_exec")]
pub fn matches<'query, 'cursor: 'query, 'tree, T: TextProvider<I>, I: AsRef<[u8]>>(
    &'cursor mut self,
    query: &'query Query,
    node: Node<'tree>,
    text_provider: T,
) -> QueryMatches<'query, 'tree, T, I> {
    let ptr = self.ptr.as_ptr();
    unsafe { ffi::ts_query_cursor_exec(ptr, query.ptr.as_ptr(), node.0) };
    QueryMatches {
        ptr,
        query,
        text_provider,
        buffer1: Vec::default(),
        buffer2: Vec::default(),
        current_match: None,
        _phantom: PhantomData,
    }
}

/// Iterate over all of the individual captures in the order that they
/// appear.
///
/// This is useful if you don't care about which pattern matched, and just
/// want a single, ordered sequence of captures.
#[doc(alias = "ts_query_cursor_exec")]
pub fn captures<'query, 'cursor: 'query, 'tree, T: TextProvider<I>, I: AsRef<[u8]>>(
    &'cursor mut self,
    query: &'query Query,
    node: Node<'tree>,
    text_provider: T,
) -> QueryCaptures<'query, 'tree, T, I> {
    let ptr = self.ptr.as_ptr();
    unsafe { ffi::ts_query_cursor_exec(ptr, query.ptr.as_ptr(), node.0) };
    QueryCaptures {
        ptr,
        query,
        text_provider,
        buffer1: Vec::default(),
        buffer2: Vec::default(),
        current_match: None,
        _phantom: PhantomData,
    }
}

